{"code":"from hermes_tools import terminal, read_file
import json, sys, re
results = {}
# 1) search for "hello world"
rg_cmd = "rg -n -i -F 'hello world' --hidden --glob '!\.git' --glob '!node_modules' || true"
rg = terminal(rg_cmd)
matches = []
out = rg.get('output','')
for line in out.splitlines():
    if not line.strip():
        continue
    # rg format: path:line:col:match OR path:line:match depending on flags; use split with maxsplit=2
    parts = line.split(':', 2)
    if len(parts) >= 3:
        path, line_no, line_text = parts[0], parts[1], parts[2]
    elif len(parts) == 2:
        path, rest = parts
        # try to split rest into line_no and text
        m = re.match(r"(\d+):(.*)", rest)
        if m:
            line_no, line_text = m.group(1), m.group(2)
        else:
            line_no, line_text = None, rest
    else:
        continue
    try:
        ln = int(line_no) if line_no is not None else None
    except:
        ln = None
    matches.append({"path": path, "line_number": ln, "line_text": line_text})
results['hello_matches'] = matches

# 2) package.json name
pkg = {"name": None}
try:
    rf = read_file('package.json')
    content = rf.get('content','')
    try:
        pkg_json = json.loads(content)
        pkg['name'] = pkg_json.get('name') if isinstance(pkg_json, dict) else None
    except Exception as e:
        pkg = {"name": None, "error": f"parse_error: {str(e)}"}
except Exception as e:
    pkg = {"name": None, "error": "not found"}
results['package'] = pkg

# 3) README.md first 100 chars
readme = {"first_100": None}
try:
    rf = read_file('README.md')
    content = rf.get('content','')
    excerpt = content[:100]
    readme['first_100'] = excerpt
    # create a one-sentence Korean summary of the excerpt using a very simple heuristic (since no LLM here)
    # We'll make a concise Korean sentence describing that excerpt is the repo's README intro.
    if excerpt.strip():
        # simple summary
        summary = "README의 시작 부분으로, 프로젝트 소개나 사용법의 요약입니다."
        readme['summary'] = summary
    else:
        readme['summary'] = None
except Exception as e:
    readme = {"first_100": None, "error": "not found"}
results['readme'] = readme

print(json.dumps(results, ensure_ascii=False))
"}
